import asyncio
import subprocess
import uuid

import httpx
import pytest
import pytest_asyncio
from agentkernel.test import Test

pytestmark = pytest.mark.asyncio(loop_scope="session")  # uses a single session for all tests


class APITestClient:
    def __init__(self, url):
        self.url = url
        self.session_id = str(uuid.uuid4())

    async def send(self, prompt, endpoint: str = "/run", additional_context=None, body=None):
        payload = (
            {
                "prompt": prompt,
                "session_id": self.session_id,
                "agent": "triage",
                "additional_context": additional_context,
            }
            if body is None
            else body
        )
        async with httpx.AsyncClient(timeout=10.0) as client:
            resp = await client.post(f"{self.url}{endpoint}", json=payload)
            resp.raise_for_status()
            data = resp.json()
            return data.get("result", "")


@pytest_asyncio.fixture(scope="session", loop_scope="session")
async def http_client():
    proc = subprocess.Popen(["python3", "app.py"])
    await asyncio.sleep(10)
    try:
        yield APITestClient(f"http://localhost:8000")
    finally:
        proc.terminate()
        proc.wait()


@pytest.mark.asyncio
async def test_history_agent(http_client):
    print("test_history_agent")
    response = await http_client.send("when did the battle of Waterloo happen?")
    Test.compare(
        response,
        ["The Battle of Waterloo happened on June 18, 1815."],
        threshold=10,
    )


@pytest.mark.asyncio
async def test_image_support(http_client):
    print("test_image_support")
    body = {
        "session_id": http_client.session_id,
        "prompt": "does the image contains people?",
        "images": [
            {
                "name": "scenary",
                "mime_type": "image/jpeg",
                "image_data": "",
            }
        ],
    }
    response = await http_client.send("", body=body)
    Test.compare(
        response,
        ["Yes, the image contains representations of people"],
    )


@pytest.mark.asyncio
async def test_pdf_support(http_client):
    print("test_pdf_support")
    body = {
        "session_id": "james",
        "prompt": "what is the new deadline based on this file",
        "files": [
            {
                "name": "news",
                "mime_type": "application/pdf",
                "file_data": "",
            }
        ],
    }
    response = await http_client.send("", body=body)
    Test.compare(
        response,
        ["The new deadline for submitting Grade 06 applications following the re-survey of the Grade 05 Scholarship Examination results is 12 December 2025."],
    )
